<template>
  <view class="container">
    <view class="wheel-wrapper">
      <view class="wheel-container">
        <canvas
          canvas-id="wheelCanvas"
          :style="{ width: width + 'px', height: height + 'px' }"
          :width="width"
          :height="height"
        ></canvas>
        <!-- 固定指针 -->
        <view class="pointer"></view>
      </view>
    </view>

    <view class="info">
      <text class="result" v-if="result">{{ result }}</text>
      <text class="hint" v-else>点击下方按钮转转盘</text>
    </view>

    <button
      type="primary"
      @click="startSpin"
      :disabled="animActive"
      class="spin-btn"
    >
      {{ animActive ? '旋转中...' : '开始转' }}
    </button>

    <!-- 选项图例（可选） -->
    <view class="legend">
      <view class="legend-item" v-for="(item, idx) in options" :key="idx">
        <view class="color-block" :style="{ backgroundColor: item.color }"></view>
        <text>{{ item.emoji }}</text>
      </view>
    </view>
  </view>
</template>

<script>
export default {
  data() {
    return {
      width: 300,            // 画布宽度
      height: 300,           // 画布高度
      radius: 120,           // 转盘半径
      centerX: 150,          // 圆心X
      centerY: 150,          // 圆心Y
      // 转盘选项：使用 emoji 表示食物，简单直观
      options: [
        { emoji: '🍔', color: '#FFB6C1' }, // 汉堡
        { emoji: '🍜', color: '#FFD700' }, // 面条
        { emoji: '🍣', color: '#87CEEB' }, // 寿司
        { emoji: '🥩', color: '#D2B48C' }, // 牛排
        { emoji: '🍕', color: '#FFA07A' }, // 披萨
        { emoji: '🥗', color: '#98FB98' }  // 沙拉
      ],
      rotateOffset: 0,       // 当前旋转偏移（弧度）
      canvasCtx: null,       // 画布上下文
      animActive: false,     // 动画是否进行中
      targetRotate: 0,       // 目标旋转角度
      result: '',            // 显示结果
      animFrame: null        // 动画帧ID
    };
  },
  computed: {
    // 每个扇形的角度
    angleStep() {
      return (2 * Math.PI) / this.options.length;
    }
  },
  onReady() {
    // 初始化画布
    this.initCanvas();
  },
  beforeDestroy() {
    // 销毁时取消动画
    if (this.animFrame) {
      cancelAnimationFrame(this.animFrame);
      this.animFrame = null;
    }
  },
  methods: {
    // 初始化画布并绘制转盘
    initCanvas() {
      // 使用 uni-app 的旧版 canvas 上下文（兼容性好）
      this.canvasCtx = uni.createCanvasContext('wheelCanvas', this);
      this.drawWheel();
    },
    // 绘制转盘（基于当前 rotateOffset）
    drawWheel() {
      const ctx = this.canvasCtx;
      if (!ctx) return;

      ctx.clearRect(0, 0, this.width, this.height);
      const step = this.angleStep;
      const offset = this.rotateOffset; // 不使用取模，保证动画连续

      this.options.forEach((item, index) => {
        const start = index * step + offset;
        const end = (index + 1) * step + offset;

        // 绘制扇形
        ctx.beginPath();
        ctx.moveTo(this.centerX, this.centerY);
        ctx.arc(this.centerX, this.centerY, this.radius, start, end);
        ctx.closePath();
        ctx.fillStyle = item.color;
        ctx.fill();

        // 绘制白色分隔线
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(this.centerX, this.centerY);
        ctx.arc(this.centerX, this.centerY, this.radius, start, end);
        ctx.closePath();
        ctx.stroke();

        // 在扇形中央绘制 emoji
        const midAngle = start + step / 2;
        const textRadius = this.radius * 0.7; // 文字离圆心的距离
        const x = this.centerX + Math.cos(midAngle) * textRadius;
        const y = this.centerY + Math.sin(midAngle) * textRadius;

        ctx.font = 'bold 28px "PingFang SC", "Helvetica Neue", "Segoe UI Emoji", sans-serif';
        ctx.fillStyle = '#2c3e50';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(item.emoji, x, y);
      });

      // 绘制中心小圆装饰
      ctx.beginPath();
      ctx.arc(this.centerX, this.centerY, 18, 0, 2 * Math.PI);
      ctx.fillStyle = '#f5f5f5';
      ctx.fill();
      ctx.strokeStyle = '#cccccc';
      ctx.lineWidth = 2;
      ctx.stroke();

      // 提交绘制
      ctx.draw();
    },
    // 开始旋转
    startSpin() {
      if (this.animActive) return;

      // 随机选择一个选项作为最终结果
      const randomIndex = Math.floor(Math.random() * this.options.length);
      const step = this.angleStep;
      // 指针固定向上（-PI/2 弧度，即12点钟方向）
      const pointerAngle = -Math.PI / 2;

      // 计算目标扇区中间角度（相对于偏移为0时的中间值）
      const targetMidAngle = randomIndex * step + step / 2;

      // 目标旋转偏移量：使该扇区中间对准指针
      // 公式：offset = pointerAngle - targetMidAngle + 圈数 * 2PI
      // 增加 5~10 圈，让转盘转得好看
      const spins = 5 + Math.floor(Math.random() * 6); // 5-10 圈
      let targetRotate = pointerAngle - targetMidAngle + spins * 2 * Math.PI;

      // 确保目标偏移大于当前偏移（保持逆时针旋转）
      while (targetRotate <= this.rotateOffset) {
        targetRotate += 2 * Math.PI;
      }

      this.targetRotate = targetRotate;
      this.animActive = true;
      this.animate();
    },
    // 动画循环
    animate() {
      if (!this.animActive) return;

      const diff = this.targetRotate - this.rotateOffset;

      // 接近目标时结束
      if (Math.abs(diff) < 0.01) {
        this.rotateOffset = this.targetRotate; // 精准到位
        this.drawWheel();

        // 取模到 [0, 2PI) 以便后续旋转不会无限增大
        this.rotateOffset = this.rotateOffset % (2 * Math.PI);
        this.drawWheel(); // 取模后重绘（视觉无变化）

        this.animActive = false;
        this.calculateResult();
        return;
      }

      // 移动步长：剩余距离的 1/8，但最小不低于 0.03 弧度
      let step = diff * 0.1;
      if (Math.abs(step) < 0.03) {
        step = diff > 0 ? 0.03 : -0.03;
      }
      this.rotateOffset += step;
      this.drawWheel();

      // 请求下一帧
      this.animFrame = requestAnimationFrame(() => {
        this.animate();
      });
    },
    // 计算当前指针指向的选项并显示结果
    calculateResult() {
      // 指针固定向上 (-PI/2)
      const pointerAngle = -Math.PI / 2;
      // 将旋转偏移归一化到 0~2PI
      const rot = this.rotateOffset % (2 * Math.PI);
      // 计算指针相对于转盘的实际角度
      let rawAngle = (pointerAngle - rot) % (2 * Math.PI);
      if (rawAngle < 0) rawAngle += 2 * Math.PI;

      const step = this.angleStep;
      const index = Math.floor(rawAngle / step);
      // 边界保护：刚好等于 2PI 时 index 可能等于 length
      const safeIndex = index >= this.options.length ? 0 : index;

      const selected = this.options[safeIndex];
      this.result = `今天推荐：${selected.emoji}`;

      uni.showToast({
        title: this.result,
        icon: 'none',
        duration: 2000
      });
    }
  }
};
</script>

